# Features: properties, virtual/override, isinstance, conditional narrowing

class Container:
    _items: list[int]

    def __init__(self):
        self._items = []

    property get count(self) -> int:
        return len(self._items)

    @virtual
    def add_item(self, value: int) -> None:
        self._items.append(value)

class BoundedContainer(Container):
    _max_capacity: int

    def __init__(self, capacity: int):
        super().__init__()
        self._max_capacity = capacity

    @override
    def add_item(self, value: int) -> None:
        if self.count < self._max_capacity:
            super().add_item(value)

    property get remaining(self) -> int:
        return self._max_capacity - self.count

class CounterContainer(Container):
    _add_count: int

    def __init__(self):
        super().__init__()
        self._add_count = 0

    @override
    def add_item(self, value: int) -> None:
